     5→//! Saddle command - Return context needed to saddle up on a Heat
     6→
     7→use std::fs;
     8→use std::path::PathBuf;
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
    14→use crate::jjrq_query::jjrq_resolve_default_heat;
    15→
    16→/// Arguments for saddle command
    17→#[derive(clap::Args, Debug)]
    18→pub struct jjrsd_SaddleArgs {
    19→    /// Path to the Gallops JSON file
    20→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    21→    pub file: PathBuf,
    22→
    23→    /// Target Heat identity (Firemark). If omitted, uses first racing heat.
    24→    pub firemark: Option<String>,
    25→}
    26→
    27→/// Run the saddle command - return Heat context
    28→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> i32 {
    29→    let gallops = match Gallops::jjrg_load(&args.file) {
    30→        Ok(g) => g,
    31→        Err(e) => {
    32→            eprintln!("jjx_saddle: error: {}", e);
    33→            return 1;
    34→        }
    35→    };
    36→
    37→    // Resolve firemark: use provided value or auto-select first racing heat
    38→    let firemark_str = match args.firemark {
    39→        Some(fm) => fm,
    40→        None => {
    41→            match jjrq_resolve_default_heat(&gallops) {
    42→                Ok(fm) => fm,
    43→                Err(e) => {
    44→                    eprintln!("jjx_saddle: error: {}", e);
    45→                    return 1;
    46→                }
    47→            }
    48→        }
    49→    };
    50→
    51→    let firemark = match Firemark::jjrf_parse(&firemark_str) {
    52→        Ok(fm) => fm,
    53→        Err(e) => {
    54→            eprintln!("jjx_saddle: error: {}", e);
    55→            return 1;
    56→        }
    57→    };
    58→
    59→    let heat_key = firemark.jjrf_display();
    60→    let heat = match gallops.heats.get(&heat_key) {
    61→        Some(h) => h,
    62→        None => {
    63→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
    64→            return 1;
    65→        }
    66→    };
    67→
    68→    // Check if heat is stabled (cannot saddle stabled heat)
    69→    if heat.status == HeatStatus::Stabled {
    70→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
    71→        return 1;
    72→    }
    73→
    74→    // Read paddock file content
    75→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
    76→        Ok(content) => content,
    77→        Err(e) => {
    78→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
    79→            return 1;
    80→        }
    81→    };
    82→
    83→    // Get recent steeplechase entries
    84→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
    85→        firemark: firemark.jjrf_as_str().to_string(),
    86→        limit: 10,
    87→    }).unwrap_or_default();
    88→
    89→    // Find first actionable pace (rough or bridled)
    90→    let mut pace_coronet: Option<String> = None;
    91→    let mut pace_silks: Option<String> = None;
    92→    let mut pace_state: Option<String> = None;
    93→    let mut spec: Option<String> = None;
    94→    let mut direction: Option<String> = None;
    95→
    96→    for coronet_key in &heat.order {
    97→        if let Some(pace) = heat.paces.get(coronet_key) {
    98→            if let Some(tack) = pace.tacks.first() {
    99→                match tack.state {
   100→                    PaceState::Rough | PaceState::Bridled => {
   101→                        pace_coronet = Some(coronet_key.clone());
   102→                        pace_silks = Some(tack.silks.clone());
   103→                        pace_state = Some(match tack.state {
   104→                            PaceState::Rough => "rough".to_string(),
   105→                            PaceState::Bridled => "bridled".to_string(),
   106→                            _ => unreachable!(),
   107→                        });
   108→                        spec = Some(tack.text.clone());
   109→                        if tack.state == PaceState::Bridled {
   110→                            direction = tack.direction.clone();
   111→                        }
   112→                        break;
   113→                    }
   114→                    _ => continue,
   115→                }
   116→            }
   117→        }
   118→    }
   119→
   120→    // Determine heat status string
   121→    let status_str = match heat.status {
   122→        HeatStatus::Racing => "racing",
   123→        HeatStatus::Stabled => "stabled",
   124→        HeatStatus::Retired => "retired",
   125→    };
   126→
   127→    // Output plain text format
   128→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   129→    println!("Paddock: {}", heat.paddock_file);
   130→    println!();
   131→    println!("Paddock-content:");
   132→    for line in paddock_content.lines() {
   133→        println!("  {}", line);
   134→    }
   135→    println!();
   136→
   137→    if let Some(coronet) = pace_coronet {
   138→        if let Some(silks) = pace_silks {
   139→            if let Some(state) = pace_state {
   140→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   141→                println!();
   142→                if let Some(spec_text) = spec {
   143→                    println!("Spec:");
   144→                    for line in spec_text.lines() {
   145→                        println!("  {}", line);
   146→                    }
   147→                    println!();
   148→                }
   149→                if let Some(dir_text) = direction {
   150→                    println!("Direction:");
   151→                    for line in dir_text.lines() {
   152→                        println!("  {}", line);
   153→                    }
   154→                    println!();
   155→                }
   156→            }
   157→        }
   158→    }
   159→
   160→    // Output recent work table
   161→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
   162→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
   163→        if let Some(ref action) = entry.action {
   164→            action == "n" || action == "A" || action == "d"
   165→        } else {
   166→            false
   167→        }
   168→    }).collect();
   169→
   170→    if !filtered_work.is_empty() {
   171→        println!("Recent-work:");
   172→
   173→        let mut table = jjrp_Table::jjrp_new(vec![
   174→            jjrp_Column::new("Commit", jjrp_Align::Left),
   175→            jjrp_Column::new("Identity", jjrp_Align::Left),
   176→            jjrp_Column::new("Subject", jjrp_Align::Left),
   177→        ]);
   178→
   179→        // Measure all rows to compute column widths
   180→        for entry in &filtered_work {
   181→            let identity_str = if let Some(ref coronet) = entry.coronet {
   182→                coronet.clone()
   183→            } else {
   184→                heat_key.clone()
   185→            };
   186→            table.jjrp_measure(&[
   187→                &entry.commit,
   188→                &identity_str,
   189→                &entry.subject,
   190→            ]);
   191→        }
   192→
   193→        // Print header and separator
   194→        table.jjrp_print_header();
   195→        table.jjrp_print_separator();
   196→
   197→        // Print data rows
   198→        for entry in &filtered_work {
   199→            let identity_str = if let Some(ref coronet) = entry.coronet {
   200→                coronet.clone()
   201→            } else {
   202→                heat_key.clone()
   203→            };
   204→            table.jjrp_print_row(&[
   205→                &entry.commit,
   206→                &identity_str,
   207→                &entry.subject,
   208→            ]);
   209→        }
   210→    }
   211→
   212→    // Check if session probe is needed (gap > 1 hour or no commits)
   213→    let last_timestamp = recent_work.first().map(|e| e.timestamp.as_str());
   214→    if crate::jjrc_core::jjrc_needs_session_probe(last_timestamp) {
   215→        println!();
   216→        match vvc::vvcp_probe().await {
   217→            Ok(probe_result) => {
   218→                println!("Session-probe:");
   219→                for line in probe_result.lines() {
   220→                    println!("  {}", line);
   221→                }
   222→            }
   223→            Err(e) => {
   224→                eprintln!("jjx_saddle: warning: probe failed: {}", e);
   225→            }
   226→        }
   227→    }
   228→
   229→    0
   230→}
