    85→        } else {
    86→            jjrn_format_heat_discussion(&firemark, &args.description)
    87→        }
    88→    } else {
    89→        eprintln!("jjx_chalk: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
    90→        return 1;
    91→    };
